INSERT INTO public.catalog_cointype VALUES (20, '2000 Réis - Efígie Floriano Peixoto', 1939, 'Prata .500', NULL, NULL, NULL, 'Moeda brasileira de 2000 réis com efígie de Floriano Peixoto, pertencente à série de réis do período pré-cruzeiro. Em 1939 ainda circulavam moedas denominadas em réis (a mudança para o cruzeiro ocorreu em 1942).', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (2, '20 Réis Império', 1869, 'Prata .900', 22.00, 5.00, 0, 'A moeda de 20 Réis de 1869 é uma das emissões do Império do Brasil, feita em prata de alta qualidade. Usada principalmente em transações do dia a dia, sua produção é parte da história monetária brasileira.', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (3, '100 Réis Imperio', 1885, 'Bronze', 27.00, 10.00, 1000000, 'A moeda de 100 Réis de 1885 foi emitida durante o período imperial brasileiro e é uma das moedas mais reconhecíveis da época.', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (18, '1000 Réis Era Vargas (Efígie Tobias Barreto)', 1939, 'Prata .500', 30.00, 10.00, NULL, 'Moeda brasileira de 1000 réis do período do Estado Novo (Era Vargas), série com efígie de Tobias Barreto. Emissão em prata 500 (50% prata).', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (5, '200 MCMI Réis República Velha', 1901, 'Bronze', 25.00, 7.50, 1000000, 'Moeda emitida durante a República Velha no Brasil, representando uma denominação de 200 réis. A moeda de 1901 é uma das várias emitidas nesse período.', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (4, '100 Réis República Velha', 1896, 'Bronze', 30.00, 12.50, 20000000, 'A moeda de 100 réis de 1896 é uma das moedas emitidas durante a República Velha no Brasil. É considerada uma moeda de valor histórico significativo.', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (6, '500 Réis República Velha 1º centenario independência', 1922, '', 30.00, 12.50, 2000000, 'Esta moeda foi emitida para celebrar o 1º centenário da independência do Brasil e apresenta o retrato de uma figura histórica importante da época.', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (7, '1000 Réis República Velha 1º centenario independência', 1922, 'Prata .900', 37.00, 20.00, 500000, 'Moeda comemorativa do 1º centenário da independência do Brasil, emitida durante a República Velha.', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (8, '1000 Réis República Velha', 1924, 'Bronze', 27.00, 10.00, 1000000, 'Moeda de 1000 réis da República Velha, emitida em 1924, é um exemplo da numeração da época e reflete a economia brasileira do início do século XX.', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (9, '500 Réis República Velha', 1924, 'Bronze', NULL, NULL, NULL, '', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (10, '1000 Réis República Velha', 1927, 'Bronze', 27.00, 10.00, 2000000, 'A moeda de 1000 Réis de 1927 foi emitida durante a República Velha no Brasil e é uma das moedas comuns do período. O desenho geralmente apresenta a efígie da República e simboliza a era de transição política no país.', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (11, '200 Réis República Velha', 1927, 'Bronze', 29.00, 12.50, 5000000, 'A moeda de 200 réis de 1927 faz parte da série emitida durante a República Velha e é conhecida por seu design que retrata a República e a cultura brasileira da época.', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (12, '500 Réis República Velha', 1928, 'Bronze', 27.00, 10.00, 5000000, 'A moeda de 500 réis de 1928 foi emitida durante a República Velha e apresenta em seu anverso a efígie da República. É uma moeda bastante colecionável e representa um período importante da história do Brasil.', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (13, '400 Réis Era Vargas', 1930, '', NULL, NULL, NULL, 'Com os dados informados (''400 Réis'', 1930, Brasil), não é possível inferir com segurança as especificações técnicas (material, diâmetro, peso e tiragem), pois há variações e emissões distintas no período e o tipo exato (série/cunhagem) não foi identificado.', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (14, '200 Réis Era Vargas', 1931, 'Bronze-alumínio', 22.00, 4.00, NULL, 'Moeda de 200 réis do Brasil do período da Era Vargas, datada de 1931, cunhada em bronze-alumínio.', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (15, '400 Réis Era Vargas', 1937, 'Bronze-alumínio', 28.00, 10.00, NULL, 'Moeda da República dos Estados Unidos do Brasil (período Era Vargas). Valor facial: 400 réis. Cunhada em bronze-alumínio; tipo comum com busto de Getúlio Vargas no anverso.', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (16, '500 Réis Era Vargas', 1938, '', NULL, NULL, NULL, '', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (17, '500 Réis Era Vargas (Machado de Assis)', 1939, 'Bronze-alumínio', 23.00, 8.00, NULL, 'Moeda brasileira de 500 réis do período do Estado Novo (Era Vargas), com efígie de Machado de Assis. Pertence à série de réis anterior à adoção do cruzeiro em 1942.', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (21, '1 Cruzeiro', 1944, 'Bronze-alumínio', 20.00, 3.00, NULL, 'Moeda do Brasil do período do Cruzeiro (1942–1967). Emissões de 1 Cruzeiro de 1944 são conhecidas em bronze-alumínio, com módulo de 20 mm e peso de 3,0 g.', 31, NULL);
INSERT INTO public.catalog_cointype VALUES (19, '2000 Réis Era Vargas (Efígie Tobias Barreto)', 1939, '', NULL, NULL, NULL, '', 31, '2026-02-22 02:45:17.450139+00');
