INSERT INTO public.history_historicalcontext VALUES (1, 'História das Moedas Brasileiras', '1500-01-01', '2023-10-01', 'A história das moedas brasileiras é rica e reflete as transformações econômicas e políticas do país desde a sua colonização. As primeiras moedas que circularam no Brasil foram as portuguesas, utilizadas a partir de 1500, quando o país foi descoberto. Com a chegada dos colonizadores, o sistema monetário era baseado principalmente em moedas de prata e ouro que eram trazidas de Portugal. Em 1690, o Brasil começou a produzir suas próprias moedas, com a cunhagem de réis, que se tornou a unidade monetária oficial durante o período colonial.
